INSERT INTO public.definitions (term, category, working_definition, likely_cargowise_source, status, open_question_note) VALUES
('File (shipment / job)', 'Grain', 'The unit of work CargoWise tracks. One shipment / job = one file. The base record everything else attaches to.', 'Job / shipment record (job file no.)', 'Agreed', 'Confirm the unique key (job_file_no) and how consol vs house files are handled.'),
('Invoice', 'Grain', 'An individual AR document posted against a file. A single file can carry many.', 'AR invoice / accounting transaction lines', 'Agreed', 'One file -> many invoices. Counting handled at the file grain (see below).'),
('Open / In-progress', 'File status', 'File is in WRK Status', 'Job header exists, no posted AR invoice', 'Proposed', NULL),
('Unbilled', 'File status', 'Either', '"Shipments with No Accounting Job Header" report', 'Proposed', 'Decide whether "unbilled" = no header, or = has header but nothing posted.'),
('Partially invoiced', 'File status', 'Open Billable Lines', 'File with >=1 AR invoice AND open billable lines', 'Proposed', 'How does the system know more is expected? (open revenue lines? job not closed?)'),
('Fully invoiced', 'File status', 'INV, CLS, CMP Status without Billable Lines', 'File with all billable lines invoiced', 'Proposed', 'Likely inferred from job close or zero remaining billable lines.'),
('Closed / finalized', 'File status', 'CLS or CMP Status', 'Job status = closed / finalized', 'Proposed', 'Distinct from "invoiced." A file can be invoiced but not closed.'),
('Initial invoice', 'Invoice event', 'The first AR invoice posted on a file. This is the event that makes the file count as invoiced (once).', 'First AR invoice by date on the file', 'Agreed', 'Count is triggered here; the first-invoice date sets the period (decision 2).'),
('Supplementary invoice', 'Invoice event', 'A subsequent AR invoice on a file already invoiced (e.g., a duty invoice after the freight invoice). New revenue, same file — does NOT re-count the file.', 'Additional AR invoice on same job_file_no', 'Agreed', 'Tracked as post-invoice activity, not a new count.'),
('Credit / re-bill', 'Invoice event', 'A correction to a prior invoice — a credit note or a re-issued invoice.', 'Credit note / reversing AR transaction', 'Proposed', 'Edge case: if a file is fully credited to zero, does it still count? (confirm)'),
('Late cost / cost true-up', 'Cost event', 'A cost added after invoicing (e.g., a vendor bill arriving late). No new revenue, but it moves margin and re-triggers activity on a file you thought was done.', 'New cost / accrual line after invoice date', 'Agreed', 'A key driver of post-invoice activity.'),
('Post-invoice activity', 'Build item', 'Any change to a file after it has been counted as invoiced — a supplementary invoice, a late cost, or a credit. Surfaced in a view so nothing slips through after the count.', 'Diff of a file''s rows across report dates, after first-invoice date', 'Build item', 'Build as its own dashboard or add to an existing one (placement is Tony''s call). Not a definitions decision.'),
('WIP (work in progress)', 'Metric', 'Report as is regardless of invoice status', 'WIP Revenue & Accrued Costs report', 'Proposed', 'Confirm exactly which lines count as WIP vs accrual.'),
('Accrual', 'Metric', 'Both accrued revenue and accrued cost lines', 'Accrued cost lines', 'Proposed', 'Note: accrued revenue is why JPR GP can run above P&L GP.'),
('Gross profit (GP)', 'Metric', 'Revenue minus cost on a file. Canonical GP = P&L-tied (posted revenue and costs only). JPR/accrued GP is kept as a separate, clearly-labeled measure ("Projected GP incl. accruals").', 'Posted AR/AP for canonical; Job Profit (Detail by Job) for projected', 'Agreed', 'DECIDED: canonical = P&L-tied; JPR shown separately and labeled.'),
('Canonical definitions (source of truth)', 'Reference', 'Argents Intelligence''s business logic/definitions are canonical, implemented as shared SQL on the Invoicing Audit''s granular row store. Dashboards read from that shared layer rather than re-deriving.', 'Argents Intelligence logic + Invoicing Audit store', 'Agreed', 'DECIDED: AI logic canonical; Invoicing Audit is the substrate (not a rebuild of AI).'),
('Reconciliation anchor', 'Reference', 'The authoritative reference results must tie to. File count -> the production Invoiced Files Audit (175); dollars (revenue, GP) -> the P&L.', 'Invoiced Files Audit; P&L / books', 'Agreed', 'DECIDED: dashboards reconcile to these, not to each other.'),
('Invoiced file (count)', 'Metric', 'A distinct file counted ONCE, at its first AR invoice. A file may carry more than one invoice but still counts once. This is the 175 (not 206).', 'Distinct job_file_no with >=1 AR invoice, by first-invoice date', 'Agreed', 'Counting grain, once-per-file, and >=1-invoice trigger are all decided (see decisions 1, 3, 4).'),
('Fiscal period', 'Reference', 'The 4-5-4 period a record is assigned to. Assigned by first-invoice date.', 'fiscal_calendar reference table', 'Agreed', 'Period = first-invoice date (decided). Pre-invoice WIP/unbilled use job/report date (no invoice yet).');
