-- =============================================================
-- Migration 009: Reference tables (Table of Truth - Cargowise.xlsx)
-- public schema: departments, definitions, job_operator, gl_codes
-- RLS on; SELECT policy for authenticated + dashboard_reader; anon blocked.
-- definitions.working_definition = workbook col G (Update Working Definition)
--   where present, else col C (Working definition).
-- =============================================================

DROP TABLE IF EXISTS public.departments CASCADE;
CREATE TABLE public.departments (
  code TEXT,
  department_name TEXT,
  PRIMARY KEY (code)
);
ALTER TABLE public.departments ENABLE ROW LEVEL SECURITY;
GRANT SELECT ON public.departments TO dashboard_reader, authenticated;
CREATE POLICY departments_read ON public.departments FOR SELECT TO authenticated, dashboard_reader USING (true);

DROP TABLE IF EXISTS public.definitions CASCADE;
CREATE TABLE public.definitions (
  term TEXT,
  category TEXT,
  working_definition TEXT,
  likely_cargowise_source TEXT,
  status TEXT,
  open_question_note TEXT,
  PRIMARY KEY (term)
);
ALTER TABLE public.definitions ENABLE ROW LEVEL SECURITY;
GRANT SELECT ON public.definitions TO dashboard_reader, authenticated;
CREATE POLICY definitions_read ON public.definitions FOR SELECT TO authenticated, dashboard_reader USING (true);

DROP TABLE IF EXISTS public.job_operator CASCADE;
CREATE TABLE public.job_operator (
  login_name TEXT,
  full_name TEXT,
  initials TEXT,
  work_phone TEXT,
  fax TEXT,
  email TEXT,
  PRIMARY KEY (login_name)
);
ALTER TABLE public.job_operator ENABLE ROW LEVEL SECURITY;
GRANT SELECT ON public.job_operator TO dashboard_reader, authenticated;
CREATE POLICY job_operator_read ON public.job_operator FOR SELECT TO authenticated, dashboard_reader USING (true);

DROP TABLE IF EXISTS public.gl_codes CASCADE;
CREATE TABLE public.gl_codes (
  code TEXT,
  act TEXT,
  description TEXT,
  details TEXT,
  type TEXT,
  margin TEXT,
  wht_type TEXT,
  tax_type TEXT,
  revenue TEXT,
  wip TEXT,
  cost TEXT,
  accrual TEXT,
  sales_grp TEXT,
  expense_grp TEXT,
  charge_grp TEXT,
  sub_grp TEXT,
  depts TEXT,
  rate_calc TEXT,
  show_on_quote TEXT,
  do_not_show_if_zero TEXT,
  cost_sell TEXT,
  dir_tax TEXT,
  incoterm TEXT,
  job_type_tax TEXT,
  tax_id TEXT,
  dir_type TEXT,
  job_type_type TEXT,
  charge_type TEXT,
  margin_percentage TEXT,
  PRIMARY KEY (code)
);
ALTER TABLE public.gl_codes ENABLE ROW LEVEL SECURITY;
GRANT SELECT ON public.gl_codes TO dashboard_reader, authenticated;
CREATE POLICY gl_codes_read ON public.gl_codes FOR SELECT TO authenticated, dashboard_reader USING (true);
